import{_ as s,o as n,c as l,O as r}from"./chunks/framework.1e3ff9a3.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"product/index.md","filePath":"product/index.md","lastUpdated":1775707265000}'),e={name:"product/index.md"};function c(i,a,t,d,p,o){return n(),l("div",null,a[0]||(a[0]=[r('<div class="brand-page-shell"><section class="brand-hero brand-hero--product"><div><p class="brand-kicker">Product Overview</p><h1>产品概览</h1><div class="brand-hero__panel"><span class="brand-pill">Product Signal</span><strong>复杂工作，简单对话；私有部署，安全省人。</strong><p>先把产品定位讲清楚，再展开场景、能力、架构和版本路线，转化路径会更顺。</p></div><p class="brand-lead"> SmartFlow 当前最准确的定义是： <strong>一个让 AI 在规则内裁决真实脚本执行、同时服务企业交付与个人入口，并逐步走向产品化和生态化的智能执行平台。</strong></p><div class="brand-chip-list"><span class="brand-chip">多租户治理</span><span class="brand-chip">可信执行</span><span class="brand-chip">免费入口</span><span class="brand-chip">CLI / Agent 路线</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="../contact.html#lead-form">申请免费试用</a><a class="cta-button" href="./scenarios.html">查看应用场景</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>SMARTFLOW // PRODUCT SIGNAL</span><span>DOC 01</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">positioning</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">trusted_ai_execution_platform</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">entry</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">free</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">team</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">enterprise</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">delivery</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">web_console</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">cli</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">local_bridge</span></span></div><div class="matrix-panel__callout">EXECUTION FIRST / PRODUCT VIEW</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">status</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">clear</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">delivery</span><span class="matrix-panel__op"> + </span><span class="matrix-panel__value">product</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">docs</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">public</span></span></div></div></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Project Layer</p><h2>项目层口径</h2><ul class="brand-list"><li>项目名：<code>SmartFlow AI Skill Platform</code></li><li>定位：<code>An Open &amp; Secure AI Agent Execution Layer</code></li><li>Slogan：<code>Make AI Work, Make Work Smart.</code></li><li>用于表达平台的技术定位和长期演进方向，从 1.0 执行底座逐步走向更强的生态协同。</li></ul></article><article class="brand-card"><p class="brand-kicker">Product Layer</p><h2>产品层口径</h2><ul class="brand-list"><li>产品名：<code>智流·智能执行平台</code></li><li>副标题：企业级业务自动化与安全执行系统</li><li>Slogan：复杂工作，简单对话；私有部署，安全省人。</li><li>用于面向客户和用户表达产品价值，而不是只强调项目代号。</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Not Building</p><h2>平台当前不是在做什么</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>不是自由聊天系统</h3><p>重点不是把模型接出来，而是让真实任务在规则里被稳定执行。</p></article><article class="brand-card brand-card--nested"><h3>不是企业后台简单裁剪版</h3><p>免费版不是把复杂后台菜单直接开放，而是做独立、轻量、可增长的正式入口。</p></article><article class="brand-card brand-card--nested"><h3>不是 demo 脚本拼装站</h3><p>它要承接企业交付、平台治理、产品升级和未来生态，不是临时脚本集合。</p></article></div></section><section class="brand-card"><p class="brand-kicker">Core Problems</p><h2>平台当前在解决什么</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><span class="brand-pill">01</span><h3>企业交付问题</h3><p>一个客户一个租户，一套后端能力中心支撑多个交付前端，平台超管统一治理客户、租户、模板、日志和审计。</p></article><article class="brand-card brand-card--nested"><span class="brand-pill">02</span><h3>AI 可信执行问题</h3><p>AI 先给出计划，再等待确认；关键执行必须留痕、可审计、可回放，而不是自由越权调用脚本。</p></article><article class="brand-card brand-card--nested"><span class="brand-pill">03</span><h3>产品入口问题</h3><p>企业交付承接收入，个人免费版承接增长入口，CLI 承接本地脚本接入与未来本地 Agent。</p></article></div></section><section class="brand-card"><p class="brand-kicker">Free Entry Reality</p><h2>免费入口的当前真实行为</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>公开入口已经成型</h3><ul class="brand-list"><li><code>/experience</code> 已经是正式免登录体验页，不再只是原型。</li><li>体验页当前提供 <code>hello_demo</code> 与 <code>clean_log_demo</code> 两个公开 demo。</li><li>公开路径当前是：体验页 -&gt; <code>/register</code> / <code>/login</code> -&gt; 正式个人版。</li><li>注册成功目前通过成功提示框承接，再跳回登录页，没有单独的注册成功页。</li></ul></article><article class="brand-card brand-card--nested"><h3>访问统计口径要写清楚</h3><ul class="brand-list"><li>体验页展示 <code>累计访问</code>、<code>今日访问</code>、<code>本月访问</code>、<code>最近一次</code> 四张统计卡片。</li><li>当前统计不是按唯一 IP 去重，而是按访问日志条数汇总。</li><li>前端用浏览器会话控制，同一浏览器会话只记录一次访问。</li><li>后端仍会记录 <code>visitor_ip</code>、<code>user_agent</code> 和 <code>referer</code> 作为公开入口日志。</li></ul></article></div></section><section class="brand-card"><p class="brand-kicker">Reading Order</p><h2>公开文档建议阅读顺序</h2><div class="brand-link-grid"><a class="brand-link-card" href="./scenarios.html"><span>Step 01</span><strong>应用场景</strong><p>先看这套平台解决哪些真实业务场景，而不是先记一堆模块名。</p></a><a class="brand-link-card" href="./capabilities.html"><span>Step 02</span><strong>核心能力</strong><p>再看多租户、可信执行、模板分发、公告治理和 CLI 桥接如何形成闭环。</p></a><a class="brand-link-card" href="./customer-flow.html"><span>Step 03</span><strong>客户流程 / 交付</strong><p>直接看客户怎么用、平台怎么交付，以及脚本热更新当前如何闭环。</p></a><a class="brand-link-card" href="./architecture.html"><span>Step 04</span><strong>架构说明</strong><p>理解后端、超管、免费版、交付前端和本地接入之间的关系。</p></a><a class="brand-link-card" href="./cli.html"><span>Step 05</span><strong>CLI 指引</strong><p>直接看当前已经落地的 <code>login / register / list / run / agent</code> 命令边界。</p></a><a class="brand-link-card" href="./deployment.html"><span>Step 06</span><strong>部署方式</strong><p>看平台如何覆盖单租户交付、平台治理、免费入口和本地混合执行。</p></a><a class="brand-link-card" href="./editions.html"><span>Step 07</span><strong>版本路线</strong><p>最后看 1.0 到 4.0 的演进逻辑，以及为什么路线不是“多加几个菜单”。</p></a></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Current Rules</p><h2>当前核心口径</h2><ul class="brand-list"><li><code>public</code> 是平台治理域，不是普通租户。</li><li>免费版是“我的技能库”入口，不是企业后台裁剪版。</li><li>平台模板、租户脚本代理、平台自有脚本三条线必须分开。</li><li>单项目先改，最后再同步到聚合壳层。</li></ul></article><article class="brand-card"><p class="brand-kicker">Good Fit</p><h2>当前适合谁</h2><ul class="brand-list"><li>需要把已有 Python / 自动化脚本接成 AI 可调度能力的团队</li><li>需要一套可继续扩租户、扩模板、扩技能的交付底座</li><li>需要同时运营企业项目和个人免费入口的独立开发者 / 小团队</li></ul></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Step</p><h2>想继续看细节，或者直接进入转化路径</h2><p class="brand-lead">你可以继续看应用场景、CLI 接入和核心能力，也可以直接提交试用 / 演示线索。</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./scenarios.html"><span>Scenario</span><strong>应用场景</strong></a><a class="brand-link-card" href="./cli.html"><span>CLI</span><strong>CLI 指引</strong></a><a class="brand-link-card" href="./customer-flow.html"><span>Delivery</span><strong>客户流程 / 交付</strong></a><a class="brand-link-card" href="./capabilities.html"><span>Capability</span><strong>核心能力</strong></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>申请试用 / 演示</strong></a></div></div></section></div>',1)]))}const m=s(e,[["render",c]]);export{b as __pageData,m as default};
